/**
 * PulseSocketDB Official Browser Client SDK (CDN Bundle v1.0.0)
 * https://cdn.pulsesocketdb.com/pulsesocketdb.min.js
 */
(function(global) {
  'use strict';

  class PulseSocketDB {
    constructor(config) {
      if (!config || !config.apiKey) {
        console.warn('PulseSocketDB: apiKey parameter is missing in constructor config.');
      }
      this.apiBase = (config && config.apiBase ? config.apiBase : 'http://localhost:3001').replace(/\/$/, '');
      this.apiKey = config ? config.apiKey : '';
      this.socket = null;
    }

    /**
     * Requisita chamadas HTTP REST
     */
    async request(path, method, body) {
      let url = `${this.apiBase}${path}`;
      let res;

      try {
        res = await fetch(url, {
          method,
          headers: {
            'Content-Type': 'application/json',
            'x-api-key': this.apiKey
          },
          body: body ? JSON.stringify(body) : undefined
        });
      } catch (directErr) {
        // Fallback automático via proxy da aplicação se o navegador bloquear conexão direta por CORS
        res = await fetch(`/api/pulsesocket-proxy${path}`, {
          method,
          headers: {
            'Content-Type': 'application/json',
            'x-api-key': this.apiKey,
            'x-target-url': this.apiBase
          },
          body: body ? JSON.stringify(body) : undefined
        });
      }

      if (!res.ok) {
        const errorText = await res.text().catch(() => '');
        let errorData;
        try {
          errorData = JSON.parse(errorText);
        } catch {
          errorData = { error: errorText || `Status ${res.status}` };
        }
        throw new Error(errorData.error || `HTTP ${res.status}`);
      }

      return res.json();
    }

    /**
     * Retorna a conexão Socket.io em tempo real
     */
    getSocket() {
      if (!this.socket && typeof io !== 'undefined') {
        this.socket = io(this.apiBase, {
          transports: ['websocket', 'polling'],
          query: { apiKey: this.apiKey },
          auth: { apiKey: this.apiKey }
        });
      }
      return this.socket;
    }

    /**
     * Retorna a referência de uma coleção de documentos
     */
    collection(name) {
      const normalized = name.replace(/^\//, '').replace(/\/$/, '').replace(/\//g, ':');
      return new CollectionReference(this, normalized);
    }
  }

  class CollectionReference {
    constructor(db, name) {
      this.db = db;
      this.name = name;
    }

    /**
     * Busca todos os documentos da coleção
     */
    async get() {
      return this.db.request(`/api/db/${this.name}`, 'GET');
    }

    /**
     * Adiciona um novo documento na coleção
     */
    async add(data) {
      return this.db.request(`/api/db/${this.name}`, 'POST', data);
    }

    /**
     * Retorna a referência a um documento por ID
     */
    doc(id) {
      return new DocumentReference(this.db, this.name, id);
    }

    /**
     * Escuta alterações em tempo real (Real-Time listener)
     */
    onSnapshot(callback) {
      const socket = this.db.getSocket();
      if (!socket) {
        console.warn('PulseSocketDB Warning: Biblioteca Socket.io client não detectada no escopo global.');
        return () => {};
      }

      socket.emit('subscribe', { collection: this.name });

      const handler = (eventData) => {
        if (!eventData) return;
        if (eventData.collection === this.name || !eventData.collection) {
          const payload = eventData.payload || eventData.data || eventData;
          callback(payload);
        }
      };

      socket.on('data_changed', handler);

      return () => {
        socket.off('data_changed', handler);
      };
    }
  }

  class DocumentReference {
    constructor(db, collectionName, id) {
      this.db = db;
      this.collectionName = collectionName;
      this.id = id;
    }

    async set(data) {
      return this.db.request(`/api/db/${this.collectionName}/${this.id}`, 'PUT', data);
    }

    async delete() {
      return this.db.request(`/api/db/${this.collectionName}/${this.id}`, 'DELETE');
    }
  }

  global.PulseSocketDB = PulseSocketDB;
})(typeof window !== 'undefined' ? window : this);
